class Solution:
    def count(self, num1: str, num2: str, min_sum: int, max_sum: int) -> int:
        MOD = 10**9 + 7

        def digit_sum(n: str) -> int:
            return sum(int(c) for c in n)

        def count_less_or_equal(n: str, target_sum: int) -> int:
            n = list(map(int, n))
            dp = [0] * (len(n) + 1)
            dp[0] = 1
            for i in range(len(n)):
                for s in range(target_sum + 1):
                    if dp[s]:
                        for d in range(0, n[i] + 1):
                            if s + d <= target_sum:
                                dp[s + d] = (dp[s + d] + dp[s]) % MOD
            return sum(dp[target_sum + 1:]) % MOD

        def count_in_range(a: str, b: str, target_sum: int) -> int:
            return (count_less_or_equal(b, target_sum) - count_less_or_equal(a, target_sum - 1)) % MOD

        total = (count_in_range(num1, num2, max_sum) - count_in_range(num1, num2, min_sum - 1)) % MOD
        return total if total >= 0 else total + MOD
